    postconditions=[{'when': 'always', 'guarantees': ['isinstance(result, int)']}, {'when': 'any(x % 2 == 0 for x in list1)', 'guarantees': ['result >= -min(x for x in list1 if x % 2 != 0)']}, {'when': 'all(x % 2 != 0 for x in list1)', 'guarantees': ['result <= max(x for x in list1 if x % 2 == 0)']}],
)

@certus(
    preconditions=['isinstance(str1, str)', 'isinstance(str2, str)', 'len(str1) == len(str2)'],
    postconditions=[{'when': 'always', 'guarantees': ['result == "Not Possible" or result >= 0']}, {'when': 'result != "Not Possible"', 'guarantees': ['result * 2 == sum(1 for c1, c2 in zip(str1, str2) if c1 != c2)']}],
)

@certus(
    preconditions=['isinstance(tuple_list, tuple)'],
    postconditions=[{'when': 'always', 'guarantees': ['result >= 48', 'result == sys.getsizeof(tuple_list)']}],
)

@certus(
    preconditions=['isinstance(arr1, list)', 'isinstance(arr2, list)', 'isinstance(m, int)', 'isinstance(n, int)', 'isinstance(k, int)', 'm == len(arr1)', 'n == len(arr2)', 'k >= 1', 'k <= m + n'],
    postconditions=[{'when': 'always', 'guarantees': ['result in arr1 + arr2', 'sorted(arr1 + arr2)[k-1] == result']}],
)

@certus(
    preconditions=['isinstance(number, int)', 'number >= 0'],
    postconditions=[{'when': 'always', 'guarantees': ['isinstance(result, bool)']}, {'when': 'result == True', 'guarantees': ['number == sum']}, {'when': 'result == False', 'guarantees': ['number != sum']}],
)

@certus(
    preconditions=['isinstance(number, int)', 'number >= 1'],
    postconditions=[{'when': 'always', 'guarantees': ['isinstance(result, tuple)', 'len(result) == 2', 'result[0] == sum(range(1, number + 1))', 'result[1] == result[0] / number']}],
)

@certus(
    preconditions=['isinstance(n, int)'],
    postconditions=[{'when': 'n % 2 == 0', 'guarantees': ['result == True']}, {'when': 'n % 2 != 0', 'guarantees': ['result == False']}, {'when': 'always', 'guarantees': ['isinstance(result, bool)']}],
)
